CREATE TABLE IF NOT EXISTS users (id BIGSERIAL PRIMARY KEY, email VARCHAR(255) UNIQUE NOT NULL, password VARCHAR(255) NOT NULL, full_name VARCHAR(255), role VARCHAR(20) DEFAULT 'USER', created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS courses (id BIGSERIAL PRIMARY KEY, title VARCHAR(255) UNIQUE NOT NULL, description TEXT, image_url VARCHAR(500), duration VARCHAR(50), instructor_name VARCHAR(255), price DOUBLE PRECISION, rating DOUBLE PRECISION DEFAULT 0.0, student_count INTEGER DEFAULT 0, created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS enrollments (id BIGSERIAL PRIMARY KEY, full_name VARCHAR(255), phone VARCHAR(50), email VARCHAR(255), city VARCHAR(100), contact_method VARCHAR(50), contact_time VARCHAR(50), notes TEXT, status VARCHAR(20) DEFAULT 'NEW', course_id BIGINT REFERENCES courses(id), created_at TIMESTAMP DEFAULT NOW());